def rel(depth,path):
    return '../'*depth + path.lstrip('/')

def clean_url(path):
    return BASE_URL + ('/' if path=='/' else path)

def lang_alt(path,lang):
    if lang=='fr':
        return '/en/' if path=='/' else '/en'+path
    return '/' if path=='/en/' else path.replace('/en','',1)

def nav_html(lang,depth,current):
    nav=NAV_FR if lang=='fr' else NAV_EN
    return ''.join(f'<a href="{rel(depth,u)}"'+(' aria-current="page"' if current==u else '')+f'>{escape(t)}</a>' for t,u in nav)

