def research_body(lang):
    fr=lang=='fr'
    hero=hero_page(lang,'Contexte frontière · 20 juillet 2026' if fr else 'Frontier context · 20 July 2026','RECHERCHE ET PREUVES' if fr else 'RESEARCH AND EVIDENCE','GoalOS is positioned where evaluated agent evolution, enterprise autonomy, cryptographic provenance and institutional governance converge.' if not fr else 'GoalOS se positionne au point de convergence de l’évolution évaluée des agents, de l’autonomie d’entreprise, de la provenance cryptographique et de la gouvernance institutionnelle.',('Open protocol papers' if not fr else 'Ouvrir les notes de protocole','/goalos-documents/research/Merkle_Roots_for_the_Validated_Skill_Graph_v114.pdf'),('View claim boundary' if not fr else 'Voir la frontière des affirmations','/en/goalos-legal/claim-boundary/' if not fr else '/goalos-legal/claim-boundary/'),'R')
    context=f'''<section><div class="wrap content-grid"><article class="prose"><h2>{'Pourquoi maintenant' if fr else 'Why now'}</h2><p>{'Les agents d’entreprise acquièrent outils, mémoire, permissions et contrôles. Les systèmes de recherche font évoluer des compétences sous évaluation. Les cadres de risque et les obligations de transparence deviennent des pratiques d’exploitation. GoalOS réunit ces axes autour d’une question : qu’est-ce qui mérite l’autorité, la mémoire et le capital?' if fr else 'Enterprise agents are acquiring tools, memory, permissions and controls. Research systems are evolving skills under evaluation. Risk frameworks and transparency obligations are becoming operating practices. GoalOS unifies these axes around one question: what deserves authority, memory and capital?'}</p><h2>{'Position scientifique' if fr else 'Scientific posture'}</h2><p>{'Les travaux récents renforcent l’importance du schéma candidat → exécution → évaluation → sélection. Ils ne démontrent pas que GoalOS, une amélioration récursive générale ou une trajectoire civilisationnelle ont été atteints. GoalOS propose l’institution qui rend ces affirmations testables, falsifiables, révisables et bornées.' if fr else 'Recent work strengthens the importance of the candidate → execution → evaluation → selection pattern. It does not demonstrate that GoalOS, general recursive improvement or civilization-scale trajectories have been achieved. GoalOS proposes the institution that makes such claims testable, falsifiable, reviewable and bounded.'}</p><h2>{'Registre de sources primaires' if fr else 'Primary source register'}</h2>{sources_html(lang)}<h2>{'Fondation GoalOS' if fr else 'GoalOS foundation'}</h2><p>{'Le Graphe de compétences validées sépare la capacité privée, les artéfacts de preuve, l’état d’engagement et l’autorité de la Chronique. La racine Merkle rend l’état compact et vérifiable; elle ne transforme pas l’inclusion en vérité. Les capacités privées peuvent rester chiffrées ou hors chaîne.' if fr else 'The Validated Skill Graph separates private capability, proof artifacts, commitment state and Chronicle authority. The Merkle root makes state compact and verifiable; it does not turn inclusion into truth. Private capabilities can remain encrypted or off-chain.'}</p><div class="download-list"><div class="download-item"><div><b>Merkle Roots for the Validated Skill Graph</b><span>{'Racines d’époque, mémoire Chronique, divulgation sélective et autorisation ENS.' if fr else 'Epoch roots, Chronicle memory, selective disclosure and ENS authorization.'}</span></div><a href="/goalos-documents/research/Merkle_Roots_for_the_Validated_Skill_Graph_v114.pdf">PDF</a></div><div class="download-item"><div><b>Private On-Chain Validated Skill Graph</b><span>{'Écritures agent directes, capsules chiffrées et preuve de politique à divulgation nulle.' if fr else 'Direct agent writes, encrypted capsules and zero-knowledge policy proof.'}</span></div><a href="/goalos-documents/research/GoalOS_Private_OnChain_Validated_Skill_Graph_v97_4.pdf">PDF</a></div></div></article><aside class="sidebar-card"><h3>{'Principes de recherche' if fr else 'Research principles'}</h3><a href="{'/proof/' if fr else '/en/proof/'}">{'Préenregistrer les portes' if fr else 'Preregister the gates'}</a><a href="{'/chronicle/' if fr else '/en/chronicle/'}">{'Séparer travail et mémoire' if fr else 'Separate work and memory'}</a><a href="{'/validated-skill-graph/' if fr else '/en/validated-skill-graph/'}">{'Engager l’état, pas l’intelligence' if fr else 'Commit state, not intelligence'}</a><a href="{'/goalos-legal/claim-boundary/' if fr else '/en/goalos-legal/claim-boundary/'}">{'Publier les limites' if fr else 'Publish the boundaries'}</a></aside></div></section>'''
    visuals=f'''<section class="section-tint"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Architecture visuelle' if fr else 'Visual architecture'}</div><h2>{'Concepts inspectables, résultats non simulés.' if fr else 'Inspectable concepts, unsimulated claims.'}</h2></div><div class="gallery"><article class="visual-card"><img src="/goalos-assets/img/private-capability-thumb.webp" alt="Private on-chain validated skill graph"><div class="body"><h3>{'Capacité privée, autorité publique' if fr else 'Private capability, public authority'}</h3><p>{'Les engagements peuvent être publics sans exposer la méthode.' if fr else 'Commitments can be public without exposing the method.'}</p><span class="ai-label">{'Visuel assisté par IA; conceptuel' if fr else 'AI-assisted; conceptual'}</span></div></article><article class="visual-card"><img src="/goalos-assets/img/value-dossier-thumb.webp" alt="GoalOS Value Realization Dossier"><div class="body"><h3>{'Réalisation de valeur' if fr else 'Value realization'}</h3><p>{'La valeur se mesure par la décision et le résultat, non par le volume d’output.' if fr else 'Value is measured by decision and outcome, not output volume.'}</p><span class="ai-label">{'Visuel assisté par IA; scénarios' if fr else 'AI-assisted; scenarios'}</span></div></article><article class="visual-card"><img src="/goalos-assets/img/validated-skill-graph-thumb.webp" alt="Validated Skill Graph"><div class="body"><h3>{'Mémoire de capacité' if fr else 'Capability memory'}</h3><p>{'Le graphe conserve les relations, preuves, droits, versions et retours arrière.' if fr else 'The graph preserves relationships, evidence, entitlements, versions and rollback.'}</p><span class="ai-label">{'Visuel assisté par IA; conceptuel' if fr else 'AI-assisted; conceptual'}</span></div></article></div></div></section>'''
