def legal_index_body(lang):
    fr=lang=='fr'
    hero=hero_page(lang,'Gouvernance publique' if fr else 'Public governance','CENTRE JURIDIQUE GOALOS' if fr else 'GOALOS LEGAL CENTRE','A claim-bounded, data-minimized, bilingual public launch. Legal protection comes from correct facts, operating controls, contracts and jurisdiction-specific advice—not absolute language.' if not fr else 'Un lancement public bilingue, minimisé en données et borné dans ses affirmations. La protection juridique vient des faits exacts, des contrôles, des contrats et des avis juridictionnels — pas de formulations absolues.',None,None,'§')
    items=[('terms','Conditions d’utilisation' if fr else 'Terms of Use'),('privacy','Confidentialité' if fr else 'Privacy'),('claim-boundary','Frontière des affirmations' if fr else 'Claim Boundary'),('regulatory','Avis réglementaire' if fr else 'Regulatory Notice'),('acceptable-use','Utilisation acceptable' if fr else 'Acceptable Use'),('web3-risk','Risques Web3' if fr else 'Web3 Risk'),('ai-transparency','Transparence IA' if fr else 'AI Transparency'),('security','Sécurité' if fr else 'Security'),('accessibility','Accessibilité' if fr else 'Accessibility'),('enterprise-services','Services d’entreprise' if fr else 'Enterprise Services')]
    root='/goalos-legal/' if fr else '/en/goalos-legal/'
    body=f'''<section><div class="wrap"><div class="legal-banner">{'Important : aucun site ne peut garantir une immunité réglementaire ou une protection juridique totale. Cette édition réduit l’exposition par minimisation des données, séparation des services, discipline des affirmations, transparence IA et portes de revue. Les déploiements réels exigent des conseillers qualifiés.' if fr else 'Important: no website can guarantee regulatory immunity or complete legal protection. This edition reduces exposure through data minimization, service separation, claim discipline, AI transparency and review gates. Real deployments require qualified counsel.'}</div><div class="grid grid-2">'''+''.join(f'<a class="card" style="text-decoration:none" href="{root+slug}/"><div class="icon">§</div><h3>{label}</h3><p>{LEGAL_DATA[slug]["fr" if fr else "en"][1]}</p></a>' for slug,label in items)+f'''</div></div></section><section class="section-dark"><div class="wrap"><div class="section-head"><div class="eyebrow">{'Architecture de réduction du risque' if fr else 'Risk-reduction architecture'}</div><h2>{'Le site public fait moins — volontairement.' if fr else 'The public site deliberately does less.'}</h2></div>{cards([('0','No accounts' if not fr else 'Aucun compte','No identity profile or server session.' if not fr else 'Aucun profil d’identité ou session serveur.'),('0','No tracking' if not fr else 'Aucun suivi','No analytics, ads, pixels or cross-site identifiers.' if not fr else 'Aucun analytics, publicité, pixel ou identifiant intersite.'),('0','No transaction' if not fr else 'Aucune transaction','No wallet, signature, token, payment or settlement.' if not fr else 'Aucun portefeuille, signature, jeton, paiement ou règlement.'),('1','Separate contract' if not fr else 'Contrat séparé','Every enterprise mission requires written authorization.' if not fr else 'Chaque mission d’entreprise exige une autorisation écrite.')],cols=4)}</div></section>'''
    return hero+body

def legal_page_body(lang,slug,depth):
    fr=lang=='fr'; title,desc,sections=LEGAL_DATA[slug]['fr' if fr else 'en']
    hero=hero_page(lang,'Gouvernance GoalOS' if fr else 'GoalOS governance',title.upper(),desc,None,None,'§')
    prose='<section><div class="wrap content-grid"><article class="prose"><div class="legal-banner">'+('Version publique v1.0.0 · En vigueur le 20 juillet 2026 · Le droit impératif et les faits réels prévalent. Révision indépendante requise avant usage commercial ou réglementé.' if fr else 'Public version v1.0.0 · Effective 20 July 2026 · Mandatory law and actual facts prevail. Independent review required before commercial or regulated use.')+'</div>'+''.join(f'<h2>{h}</h2><p>{p}</p>' for h,p in sections)+'</article>'+legal_sidebar(lang,depth)+'</div></section>'
    return hero+prose

def write_legal_pages():
    (OUT/'goalos-legal/index.html').write_text(page_doc('fr','/goalos-legal/','Centre juridique GoalOS','Conditions, confidentialité, frontières de revendication, réglementation, sécurité et services d’entreprise.',legal_index_body('fr'),depth=1,current='/goalos-legal/'),encoding='utf-8')
    (OUT/'en/goalos-legal/index.html').write_text(page_doc('en','/en/goalos-legal/','GoalOS Legal Centre','Terms, privacy, claim boundaries, regulation, security and enterprise services.',legal_index_body('en'),depth=2,current='/en/goalos-legal/'),encoding='utf-8')
    for slug in LEGAL_DATA:
      tf=LEGAL_DATA[slug]['fr'][0]; te=LEGAL_DATA[slug]['en'][0]
      p=f'/goalos-legal/{slug}/'; (OUT/'goalos-legal'/slug/'index.html').write_text(page_doc('fr',p,tf+' · GoalOS',LEGAL_DATA[slug]['fr'][1],legal_page_body('fr',slug,2),depth=2,current='/goalos-legal/'),encoding='utf-8')
      ep=f'/en/goalos-legal/{slug}/'; (OUT/'en/goalos-legal'/slug/'index.html').write_text(page_doc('en',ep,te+' · GoalOS',LEGAL_DATA[slug]['en'][1],legal_page_body('en',slug,3),depth=3,current='/en/goalos-legal/'),encoding='utf-8')

def write_misc():
    (OUT/'.nojekyll').write_text('',encoding='utf-8')
    (OUT/'goalos-assets/icons/favicon.svg').write_text('''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><rect width="64" height="64" rx="16" fill="#071a2e"/><circle cx="32" cy="32" r="23" fill="none" stroke="#e7c978" stroke-width="2"/><text x="32" y="42" text-anchor="middle" font-family="Georgia,serif" font-size="31" font-weight="700" fill="#e7c978">G</text></svg>''',encoding='utf-8')
    manifest={'name':'MONTREAL.AI × GoalOS','short_name':'GoalOS','start_url':'/','display':'standalone','background_color':'#fbf8f0','theme_color':'#071a2e','lang':'fr-CA','icons':[{'src':'/goalos-assets/icons/favicon.svg','sizes':'any','type':'image/svg+xml'}]}
    (OUT/'manifest.webmanifest').write_text(json.dumps(manifest,ensure_ascii=False,indent=2),encoding='utf-8')
    (OUT/'robots.txt').write_text('''User-agent: *\nAllow: /\nSitemap: https://montrealai.github.io/sitemap.xml\n\n# Public availability does not grant a licence for bulk commercial model training.\n''',encoding='utf-8')
    (OUT/'ai.txt').write_text('''MONTREAL.AI × GoalOS — AI and content transparency\nVersion: 1.0.0\nDate: 2026-07-20\n\nSome visuals and text were created with AI assistance and human review. Conceptual visuals are labelled and are not empirical results. Time-sensitive claims link to primary sources in source-register.json. Public availability does not grant rights beyond an express licence.\nContact: secretariat@montreal.ai\n''',encoding='utf-8')
    (OUT/'humans.txt').write_text('''MONTREAL.AI × GoalOS\nCategory architecture and public direction: Vincent Boucher / MONTREAL.AI\nBilingual public launch edition: 2026-07-20\nContact: secretariat@montreal.ai\n''',encoding='utf-8')
    (OUT/'source-register.json').write_text(json.dumps({'schema':'montrealai.goalos.source-register.v1','version':VERSION,'as_of':DATE,'sources':SOURCES,'boundaries':['Sources do not endorse GoalOS.','External facts may change.','GoalOS architecture claims are separate from empirical customer results.']},ensure_ascii=False,indent=2),encoding='utf-8')
    pages=['/','/goalos/','/proof-missions/','/proof-offices/','/frontier-masterclass/','/autonomous-money-machine/','/agi-jobs/','/chronicle/','/validated-skill-graph/','/agent-identity/','/treasury/','/proof/','/research/','/company/','/contact/','/downloads/','/goalos-legal/']+[f'/goalos-legal/{s}/' for s in LEGAL_DATA]
    pages += ['/en/']+[('/en'+p if p!='/' else '/en/') for p in pages[1:]]
    urls=''.join(f'<url><loc>{clean_url(p)}</loc><lastmod>{DATE}</lastmod><changefreq>{"weekly" if p in ["/","/en/"] else "monthly"}</changefreq><priority>{"1.0" if p in ["/","/en/"] else "0.7"}</priority></url>' for p in pages)
    (OUT/'sitemap.xml').write_text('<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">'+urls+'</urlset>',encoding='utf-8')
    # Bilingual 404
    b='''<section class="page-hero"><div class="wrap page-hero-grid"><div><div class="eyebrow">404 · Page introuvable / Page not found</div><h1>RETOUR À L’INSTITUTION</h1><p class="lead">Cette adresse ne fait pas partie de la présente édition. This address is not part of the current edition.</p><div class="actions"><a class="btn primary" href="/">Accueil français</a><a class="btn dark" href="/en/">English home</a><a class="btn" href="/downloads/">Téléchargements / Downloads</a></div></div><div class="page-hero-art"><div class="sigil">404</div></div></div></section>'''
    (OUT/'404.html').write_text(page_doc('fr','/404.html','404 · MONTREAL.AI × GoalOS','Page introuvable / Page not found.',b,depth=0,current='/'),encoding='utf-8')
    be='''<section class="page-hero"><div class="wrap page-hero-grid"><div><div class="eyebrow">404 · Page not found / Page introuvable</div><h1>RETURN TO THE INSTITUTION</h1><p class="lead">This address is not part of the current edition. Cette adresse ne fait pas partie de la présente édition.</p><div class="actions"><a class="btn primary" href="/en/">English home</a><a class="btn dark" href="/">Accueil français</a><a class="btn" href="/en/downloads/">Downloads / Téléchargements</a></div></div><div class="page-hero-art"><div class="sigil">404</div></div></div></section>'''
    (OUT/'en/404.html').write_text(page_doc('en','/en/404.html','404 · MONTREAL.AI × GoalOS','Page not found / Page introuvable.',be,depth=1,current='/en/'),encoding='utf-8')
    # deployment docs
    (OUT/'README.md').write_text('''# MONTREAL.AI × GoalOS — Bilingual GitHub Pages Website\n\nFrench-primary, fully mirrored English static launch site. No accounts, analytics, server forms, wallet connection, payments or external runtime dependencies.\n\n## Deploy safely to MontrealAI/MontrealAI.github.io\n\nThis package is an **overlay**. It replaces the root `index.html` and adds uniquely namespaced `goalos-*` paths while preserving the repository's existing legacy files and URLs.\n\n1. Back up the current root `index.html`.\n2. Extract the deploy ZIP into the repository root, allowing the listed overlay files to replace their prior versions.\n3. Do not delete unrelated existing directories.\n4. Review `SITE_OVERLAY_MANIFEST.json`.\n5. Commit to a review branch, inspect the diff, then merge to `master`.\n6. In repository Settings → Pages, use the existing branch/root publishing configuration.\n7. Test French, English, legal, downloads, mobile and legacy URLs.\n\nThe repository is large; an Actions workflow that uploads the entire repository as a Pages artifact may be inefficient. Direct branch publication is therefore the recommended deployment path unless the repository architecture is separately refactored.\n\n## Legal boundary\n\nNo package can guarantee immunity from law or regulation. Independent Quebec, Canadian and international counsel should review the live operator, entity names, contracts, products, data flows and jurisdictions before activation.\n''',encoding='utf-8')
    (OUT/'DEPLOYMENT.md').write_text('''# Deployment and Rollback\n\n## Recommended deployment\n\n- Target repository: `MontrealAI/MontrealAI.github.io`\n- Target branch: `master`\n- Target location: repository root\n- Publishing: existing GitHub Pages branch/root configuration\n\n## Pre-deployment\n\n- Create a branch such as `goalos-bilingual-launch-v1`.\n- Preserve the prior `index.html` in Git history.\n- Confirm all current legacy routes remain present.\n- Run the included link and browser checks.\n- Obtain independent legal review of the production entity, contact details and live services.\n\n## Rollback\n\nRevert the launch commit or restore the previous root `index.html`. The overlay does not intentionally delete legacy paths.\n\n## Security headers\n\nGitHub Pages does not allow arbitrary response headers. The site therefore includes a restrictive meta Content Security Policy. Higher-assurance hosting should add server-level HSTS, CSP, Permissions-Policy, Referrer-Policy and X-Content-Type-Options headers.\n''',encoding='utf-8')
    # validation workflow only, not Pages deployment
    wf='''name: Verify GoalOS bilingual site\non:\n  workflow_dispatch:\n  pull_request:\n    paths:\n      - 'index.html'\n      - 'en/**'\n      - 'goalos-*/**'\n      - 'goalos/**'\n      - 'proof-*/**'\n      - 'frontier-masterclass/**'\n      - 'autonomous-money-machine/**'\n      - 'agi-jobs/**'\n      - 'chronicle/**'\n      - 'validated-skill-graph/**'\n      - 'agent-identity/**'\n      - 'treasury/**'\n      - 'research/**'\n      - 'company/**'\n      - 'contact/**'\n      - 'downloads/**'\njobs:\n  verify:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with:\n          python-version: '3.12'\n      - run: python scripts/verify_site.py\n'''
    (OUT/'.github/workflows/goalos-site-verify.yml').write_text(wf,encoding='utf-8')
    (OUT/'scripts').mkdir(exist_ok=True)
    verify='''from pathlib import Path\nfrom html.parser import HTMLParser\nimport sys\nROOT=Path(__file__).resolve().parents[1]\nclass P(HTMLParser):\n def __init__(self): super().__init__(); self.links=[]\n def handle_starttag(self,t,a):\n  d=dict(a)\n  if t in ('a','link','script','img'):\n   u=d.get('href') or d.get('src')\n   if u:self.links.append(u)\nerrors=[]\nfor f in ROOT.rglob('*.html'):\n p=P(); p.feed(f.read_text(encoding='utf-8'))\n for u in p.links:\n  if u.startswith(('http:','https:','mailto:','tel:','#','data:')): continue\n  q=(ROOT/u.lstrip('/')) if u.startswith('/') else (f.parent/u)\n  q=Path(str(q).split('#')[0].split('?')[0])\n  if q.is_dir(): q=q/'index.html'\n  if not q.exists(): errors.append(f'{f.relative_to(ROOT)} -> {u}')\nif errors:\n print('Broken links:'); print('\\n'.join(errors)); sys.exit(1)\nprint('GoalOS site links: PASS')\n'''
    (OUT/'scripts/verify_site.py').write_text(verify,encoding='utf-8')

def run():
    write_home('fr'); write_home('en'); write_product_pages(); write_special_pages(); write_legal_pages(); write_misc()

if __name__=='__main__':
    run()
    print('generated',OUT)
